#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *izlaz;
    char *imena[] = {"Ana", "Marko", "Lejla"};
    float bodovi[] = {12.9823, 19.1283, 17.8};
    int vel = 3, i;

    izlaz = fopen("studenti.txt", "w");
    if (izlaz == NULL) {
        printf("Otvaranje datoteke studenti.txt nije uspjelo!\n");
        return 1;
    }

    for (i = 0; i < vel; i++) {
        fprintf(izlaz, "Bodovi: %.2f; Ime: %s\n", bodovi[i], imena[i]);
    }

    printf("Upis zavrsen.\n");

    fclose(izlaz);
    return 0;
}
